<?php $adminTitle='LMS Quizzes'; include __DIR__.'/../includes/admin-header.php'; include __DIR__.'/../includes/admin-sidebar.php'; if($_SERVER['REQUEST_METHOD']==='POST'&&verify_csrf($_POST['csrf_token']??null)){ $pdo->prepare('INSERT INTO lms_quizzes (course_id,title,pass_mark,status) VALUES (?,?,?,?) ON DUPLICATE KEY UPDATE title=VALUES(title),pass_mark=VALUES(pass_mark),status=VALUES(status)')->execute([(int)$_POST['course_id'],trim($_POST['title']),(int)$_POST['pass_mark'],$_POST['status']]); header('Location: lms-quizzes.php'); exit; } $courses=get_courses($pdo,false); $rows=$pdo->query('SELECT q.*,c.title course_title FROM lms_quizzes q JOIN lms_courses c ON c.id=q.course_id ORDER BY c.title')->fetchAll(); ?><h1>Quizzes</h1><form class="glass-card mb-4" method="post"><input type="hidden" name="csrf_token" value="<?= e(csrf_token()); ?>"><div class="row g-3"><div class="col-md-5"><select class="form-select" name="course_id"><?php foreach($courses as $c): ?><option value="<?= (int)$c['id']; ?>"><?= e($c['title']); ?></option><?php endforeach; ?></select></div><div class="col-md-4"><input class="form-control" name="title" placeholder="Quiz title" required></div><div class="col-md-1"><input class="form-control" name="pass_mark" value="70"></div><div class="col-md-2"><select class="form-select" name="status"><option>Published</option><option>Draft</option></select></div><div class="col-12"><button class="btn btn-premium">Save Quiz</button></div></div></form><div class="glass-card"><table class="table table-dark"><tr><th>Course</th><th>Quiz</th><th>Pass</th><th>Status</th></tr><?php foreach($rows as $r): ?><tr><td><?= e($r['course_title']); ?></td><td><?= e($r['title']); ?></td><td><?= (int)$r['pass_mark']; ?>%</td><td><?= e($r['status']); ?></td></tr><?php endforeach; ?></table></div><?php include __DIR__.'/../includes/admin-footer.php'; ?>